import React from 'react';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import ArtNav from './ArtNav';
//pages
import Vector from './pages/Vector';
import PenAndInk from './pages/PenAndInk';
import Books from './pages/Books';


export default class Artwork extends React.Component{

  //state
  state = {
    isDisplayed: Vector,
    on: true
}
//toggle
// toggle = (e)=>{
//     e.preventDefault();
//       //set state
//        this.setState({
//     //      isOpen: !this.state.isOpen,
//        });    
//     } 
//display vector
displayVector = (e)=>{
  e.preventDefault();
     this.setState({
          isDisplayed: Vector
     });    
  } 
  //display pen and ink
 displayPenInk = (e)=>{
    e.preventDefault();
    this.setState({
         isDisplayed: PenAndInk
    });
}
  //display books
 displayBooks = (e)=>{
    e.preventDefault();
    this.setState({
         isDisplayed: Books
    });
}
isDisplayed = (e)=>{
    e.preventDefault();
    this.setState({
        on: !this.state.on
    });
}
//render method
    render(){


        return(
            
   <Router basename='/'> 
    <div >  
    <ArtNav />
          <div>
          <Switch>    
                <Route exact path="/portfolio/Artwork/Vector" component={Vector}  />
                <Route path="/portfolio/Artwork/Vector" component={Vector}  />
                <Route path="/PenAndInk"  component={PenAndInk} />
                <Route path="/Books" component={Books} />
            </Switch>
          </div>
      </div>
</Router>

        )   
    }
}


