import React from 'react';
import { Link } from 'react-router-dom';


const hapticVibrate = ()=> navigator.vibrate(20);


 export default class Navigation extends React.Component {

        render(){
            return (  
                 
        <div> 
            <ul className="nav justify-content-center bangers">
                <Link onClick={hapticVibrate} className="nav-link" to="/Artwork/Vector">
                    <li>Artwork</li>
                 </Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/Animation">
                    <li>Animation</li>
                    </Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/Games">
                    <li>Games</li>
                </Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/">
                <li>Home</li>
                </Link>
                <a onClick={hapticVibrate} className="nav-link"  href="mailto:rossmarinaro@gmail.com" target="_blank"  rel="noopener noreferrer">
                <li>Contact</li>
                </a>  
            </ul>
        </div> 
                 
            )
          
        }
       
}
   

