import React from 'react';
//vector images
import vector1 from '../../static/vectors/thumbnails/1.png';
import vector2 from '../../static/vectors/thumbnails/2.png';
import vector3 from '../../static/vectors/thumbnails/3.png';
import vector4 from '../../static/vectors/thumbnails/4.png';

export default class Vector extends React.Component{

 render(){
     return (
         <div >
             <figure className="gallery">
                 <ul>
                     <li><a className="image-gallery-link" href={vector1}> <img src={vector1} alt="vector illustration"/></a></li>
                     <li><a className="image-gallery-link" href={vector2}> <img src={vector2} alt="vector illustration"/></a></li>
                     <li><a className="image-gallery-link" href={vector3}> <img src={vector3} alt="vector illustration"/></a></li>
                     <li><a className="image-gallery-link" href={vector4}> <img src={vector4} alt="vector illustration"/></a></li>
                 </ul>
                <figcaption className="digitizer">Vector Illustration</figcaption>
             </figure>
         </div>
        )  
    }
}
